下面是用C++编写的程序，根据输入的6个整数，计算并输出其中是奇数且是3的倍数的数的平均值（保留4位小数）：

```c++
#include <iostream>
#include <iomanip>

int main() {
    int nums[6];
    int count = 0;
    int sum = 0;

    std::cout << "请输入6个整数：" << std::endl;
    for(int i = 0; i < 6; i++) {
        std::cin >> nums[i];
        if(nums[i] % 2 == 1 && nums[i] % 3 == 0) {
            count++;
            sum += nums[i];
        }
    }

    if(count > 0) {
        double average = static_cast<double>(sum) / count;
        std::cout << "奇数且是3的倍数的数的平均值为：" << std::fixed << std::setprecision(4) << average << std::endl;
    } else {
        std::cout << "没有符合条件的数！" << std::endl;
    }

    return 0;
}
```

